```
функција SquareSumOfOfOddЦели (n, arr) {
  нека сума = 0;
  за (нека i = 0; i < n; i++) {
    ако (arr[i] % 2 !== 0) {
      сума += arr[i];
    }
  }
  повратна сума * сума;
}

